INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('M2_L1_A', 'M2', 1, 'A', 'Physical modeling', '24 small objects (e.g., beans or blocks)', 'Say: ''We are planting a small garden. Make 3 rows, and put 4 plants in each row. How many plants did we use in total?''', 'Child arranges objects into a 3x4 array and correctly counts 12 total.', 'Child makes uneven rows, random groups, or miscounts.', 'How does arranging them in rows make it easier to count them all?', '{"default":{"objects":["blocks","tiles","cards"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["stones","bottle caps","sticks"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('M2_L1_B', 'M2', 1, 'B', 'Physical modeling', 'A box or outline on paper, Small square tiles or blocks', 'Say: ''This box is the floor of a new room. We are laying square tiles. Put 5 tiles in a row along one wall, and keep making rows until you have 4 rows. How many tiles cover the floor?''', 'Child creates a 4x5 array inside the boundary and counts 20 total tiles.', 'Child places tiles randomly without rows, or miscounts the total.', 'If we took away one entire row, how many tiles would be left?', '{"default":{"objects":["blocks","tiles","cards"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["stones","bottle caps","sticks"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('M2_L1_C', 'M2', 1, 'C', 'Physical modeling', 'Paper, Pencil, 15 small objects', 'Say: ''We have 15 books. We want to put them on shelves so that every shelf has exactly 5 books. Make the piles, then draw a picture of the shelves.''', 'Child makes 3 equal piles of 5, then draws a representation showing 3 shelves with 5 items each.', 'Child makes unequal piles, or draws a picture that doesn''t match the physical model.', 'How did you know you needed exactly 3 shelves?', '{"default":{"objects":["blocks","tiles","cards"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["stones","bottle caps","sticks"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('M2_L2_A', 'M2', 2, 'A', 'Structured translation', NULL, 'Say: ''A baker has 4 trays of cookies. Each tray holds 6 cookies. Draw a picture of the trays, then write a math sentence (equation) that shows how to find the total number of cookies.''', 'Child draws 4 groups of 6 and writes ''4 x 6 = 24'' or ''6 + 6 + 6 + 6 = 24''.', 'Child writes the wrong numbers, adds 4 and 6 to get 10, or draws an incorrect picture.', 'Why did you use the number 6 four times in your model?', '{"default":{"objects":["blocks","tiles","cards"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["stones","bottle caps","sticks"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('M2_L2_B', 'M2', 2, 'B', 'Structured translation', NULL, 'Say: ''We are building a fence. The yard is shaped like a rectangle. It is 5 steps long and 3 steps wide. Draw the yard and write an equation to show how many steps of fence we need to go all the way around.''', 'Child draws a rectangle, labels the sides (5, 3, 5, 3), and writes an equation like ''5 + 3 + 5 + 3 = 16''.', 'Child only adds 5 + 3 = 8, forgetting the other two sides.', 'Why are there four numbers in your addition sentence instead of just two?', '{"default":{"objects":["blocks","tiles","cards"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["stones","bottle caps","sticks"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('M2_L2_C', 'M2', 2, 'C', 'Structured translation', NULL, 'Say: ''I asked 5 friends what their favorite color is. 3 said Red, 2 said Blue. Draw a bar graph to show this data, then write a math sentence showing the total number of friends I asked.''', 'Child draws a bar graph with ''Red'' at 3 and ''Blue'' at 2, and writes ''3 + 2 = 5''.', 'Child draws the graph incorrectly (e.g., no labels, wrong heights) or writes an incorrect equation.', 'How does your graph show the same information as your math sentence?', '{"default":{"objects":["blocks","tiles","cards"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["stones","bottle caps","sticks"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('M2_L3_A', 'M2', 3, 'A', 'Error detection', NULL, 'Say: ''A word problem says: There are 5 cars. Each car has 4 wheels. My friend drew 5 circles and 4 circles, and wrote 5 + 4 = 9 wheels. What is wrong with their model?''', 'Child explains that the friend added cars and wheels together, instead of putting 4 wheels ON EACH of the 5 cars.', 'Child thinks the math is correct because 5 + 4 is 9.', 'How should the drawing look to correctly show wheels on cars?', '{"default":{"objects":["blocks","tiles","cards"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["stones","bottle caps","sticks"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('M2_L3_B', 'M2', 3, 'B', 'Error detection', NULL, 'Say: ''The problem is to find the perimeter of a rectangular field that is 6 meters long and 2 meters wide. My friend wrote 6 + 2 = 8 meters. What part of the real world did they forget?''', 'Child identifies that a rectangle has four sides, and the friend only accounted for two of them.', 'Child agrees with the friend''s answer.', 'If you only build 8 meters of fence, what will the field look like?', '{"default":{"objects":["blocks","tiles","cards"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["stones","bottle caps","sticks"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('M2_L3_C', 'M2', 3, 'C', 'Error detection', NULL, 'Say: ''My friend collected data on favorite pets. They tallied 4 Dogs, 3 Cats, and 2 Fish. To find the total, they multiplied 4 x 3 x 2. Why does their math model not fit the real world?''', 'Child explains that to find a total number of different things combined, you must add, not multiply.', 'Child thinks multiplying is just another way to get a big total.', 'If you actually multiply 4 x 3 x 2, you get 24. Do you have 24 pets here?', '{"default":{"objects":["blocks","tiles","cards"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["stones","bottle caps","sticks"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('M2_L4_A', 'M2', 4, 'A', 'Design and Justification', NULL, 'Say: ''Invent a word problem about our house that requires multiplication to solve it. Tell me the problem, draw a picture to model it, and write the math equation.''', 'Child creates a valid scenario involving equal groups (e.g., ''There are 3 windows, and each has 2 curtains''), models it accurately, and writes the correct equation.', 'Child creates an addition problem (e.g., ''3 windows and 2 doors''), or the model/equation doesn''t match the story.', 'How do you know for sure your story requires multiplication and not just addition?', '{"default":{"objects":["blocks","tiles","cards"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["stones","bottle caps","sticks"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);